class Solution:
    def distinctSequences(self, n: int) -> int:
        MOD = 10**9 + 7
        dp = [[0]*7 for _ in range(n+1)]
        for i in range(1, 7):
            dp[1][i] = 1
        for i in range(2, n+1):
            for j in range(1, 7):
                for k in range(1, 7):
                    if gcd(j, k) == 1:
                        dp[i][j] = (dp[i][j] + dp[i-1][k]) % MOD
                if i >= 4 and dp[i-3][j]:
                    dp[i][j] = (dp[i][j] - dp[i-3][j]) % MOD
        return sum(dp[n]) % MOD

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a
